const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json;
  const total = Number(j.total || 0);
  const n = Number(j.n || 0);
  const fmt = x => Number(x||0).toLocaleString('es-AR');
  let text;
  if (n === 0) {
    const opts = ['🧘 Hoy no anotaste gastos. Buen día para la billetera.', '🎉 Día sin gastos registrados. ¡Bien ahí!', '✨ Hoy no me llegó nada. Si te olvidaste algo, lo podés cargar ahora.'];
    text = opts[Math.floor(Math.random()*opts.length)];
  } else {
    let body = `📊 *Resumen de hoy*\nGastaste $${fmt(total)} en ${n} ${n===1?'movimiento':'movimientos'}`;
    if (j.top_category) body += `\nMás fuerte: ${j.top_category} ($${fmt(j.top_amount)})`;
    text = body;
  }
  out.push({ json: { phone: j.phone, instance: 'chefin', remoteJid: j.phone + '@s.whatsapp.net', replyText: text, userId: j.user_id }});
}
return out;
